import json
from kafka import KafkaConsumer

class FinancialTransactionConsumer:
    def __init__(self, topic):
        self.topic = topic
        self.consumer = KafkaConsumer(bootstrap_servers=['localhost:9092'], group_id='my-group', auto_offset_reset='earliest')

    def consume(self):
        for message in self.consumer:
            try:
                transaction = json.loads(message.value)
                if transaction['type'] == 'deposit':
                    # Execute deposit logic
                    print("Deposit of $", transaction['amount'], "received from account", transaction['account_id'])
                elif transaction['type'] == 'withdrawal':
                    # Execute withdrawal logic
                    print("Withdrawal of $", transaction['amount'], "from account", transaction['account_id'])
                else:
                    # Handle unknown transaction type
                    print("Unknown transaction type:", transaction['type'])
            except json.JSONDecodeError as e:
                print("Invalid JSON message received:", e)
            except KeyError as e:
                print("Missing key in JSON message:", e)

if __name__ == '__main__':
    consumer = FinancialTransactionConsumer('my-topic')
    consumer.consume()